window.GLOSSARY = {"version":1,"generated":"2026-07-23","terms":[{"term":"depression","aliases":["major depressive disorder","major depressive episode","unipolar depression","depressive episode","major depression","depression","mdd"],"def":"A mood disorder with ≥2 weeks of low mood or loss of interest plus changes in sleep, appetite, energy, and concentration.","wiki":"mdd","category":"disorder"},{"term":"sedation","aliases":["somnolence","drowsiness","sedation","sedating"],"def":"Drug-induced drowsiness and reduced alertness (CNS depression); additive and dangerous when sedatives are combined.","wiki":null,"category":"adverse-effect"},{"term":"anticholinergic","aliases":["central antimuscarinic","muscarinic blockade","anticholinergics","anticholinergic","antimuscarinic"],"def":"A drug blocking muscarinic acetylcholine receptors, causing dry mouth, constipation, blurred vision, and confusion.","wiki":null,"category":"pharmacology"},{"term":"bipolar disorder","aliases":["bipolar ii disorder","bipolar depression","bipolar i disorder","bipolar disorder","manic depression","bipolar ii","bipolar i","bipolar"],"def":"A mood disorder with episodes of mania or hypomania and usually depression; bipolar depression is its depressive pole.","wiki":"bipolar","category":"disorder"},{"term":"extrapyramidal symptoms","aliases":["extrapyramidal side effects","extrapyramidal symptoms","extrapyramidal","eps"],"def":"Drug-induced movement disorders from D2 blockade — acute dystonia, parkinsonism, akathisia and, later, tardive dyskinesia.","wiki":"eps","category":"syndrome"},{"term":"antipsychotic","aliases":["antipsychotics","antipsychotic","neuroleptics","neuroleptic"],"def":"A drug that treats psychosis mainly by blocking dopamine D2 receptors; split into first- and second-generation agents.","wiki":null,"category":"class"},{"term":"insomnia","aliases":["sleep-maintenance insomnia","sleep-onset insomnia","insomnia disorder","sleeplessness","insomnia"],"def":"Difficulty falling or staying asleep, or early-morning waking, despite adequate opportunity, with daytime consequences.","wiki":"insomnia","category":"disorder"},{"term":"insomnia disorder","aliases":["insomnia disorder","chronic insomnia","insomnia"],"def":"Difficulty falling or staying asleep despite adequate opportunity, with daytime consequences; CBT-I is first-line.","wiki":"insomnia","category":"disorder"},{"term":"half-life","aliases":["elimination half-life","half-life","half life"],"def":"The time for a drug's blood level to fall by half; it governs dosing frequency and how long effects and withdrawal last.","wiki":null,"category":"pharmacology"},{"term":"ssri","aliases":["selective serotonin reuptake inhibitor","ssris","ssri"],"def":"Selective serotonin reuptake inhibitor — first-line antidepressants and anxiolytics (e.g., sertraline, escitalopram).","wiki":null,"category":"class"},{"term":"benzodiazepine","aliases":["benzodiazepines","benzodiazepine","benzos","benzo"],"def":"A GABA-A enhancer used for anxiety, insomnia, seizures, and withdrawal; carries tolerance, dependence, and sedation risk.","wiki":null,"category":"class"},{"term":"agitation","aliases":["psychomotor agitation","behavioural emergency","behavioral emergency","acute agitation","agitation","combative"],"def":"A behavioural emergency of escalating motor activity and arousal that risks harm; managed with de-escalation then medication.","wiki":"agitation","category":"symptom"},{"term":"akathisia","aliases":["inner restlessness","akathisias","akathisia","akathisic"],"def":"A distressing inner restlessness with an urge to move; a common antipsychotic effect treated first-line with propranolol.","wiki":"eps","category":"adverse-effect"},{"term":"dependence","aliases":["physiological dependence","physical dependence","dependence"],"def":"A state in which stopping a drug provokes withdrawal; develops with benzodiazepines, opioids and other agents.","wiki":null,"category":"pharmacology"},{"term":"drug-induced parkinsonism","aliases":["drug-induced parkinsonism","drug-induced parkinsonian","drug induced parkinsonism","parkinsonism","parkinsonian"],"def":"Antipsychotic-caused tremor, rigidity and slowed movement mimicking Parkinson disease, from D2 blockade in the striatum.","wiki":"eps","category":"adverse-effect"},{"term":"tardive dyskinesia","aliases":["choreoathetoid movements","orofacial dyskinesia","tardive dyskinesia","tardive dystonia","choreoathetoid","tardive"],"def":"Involuntary, often irreversible choreoathetoid movements (lip-smacking, tongue-thrusting) from long-term dopamine blockade.","wiki":"tardive-dyskinesia","category":"adverse-effect"},{"term":"tca","aliases":["tricyclic antidepressant","tetracyclic","tricyclics","tricyclic","tcas","tca"],"def":"An older antidepressant class that is effective but anticholinergic and cardiotoxic in overdose via sodium-channel blockade.","wiki":null,"category":"class"},{"term":"psychosis","aliases":["psychotic symptoms","psychotic features","psychosis","psychotic"],"def":"A loss of contact with reality — hallucinations, delusions, or disorganized thinking — seen across many conditions.","wiki":"schizophrenia","category":"symptom"},{"term":"schizophrenia","aliases":["psychotic disorder","schizophrenia","schizophrenic","psychosis"],"def":"A chronic psychotic disorder with positive symptoms (delusions, hallucinations), negative symptoms and cognitive impairment.","wiki":"schizophrenia","category":"disorder"},{"term":"mania","aliases":["manic episode","acute mania","mania","manic"],"def":"An abnormally elevated or irritable mood with high energy, reduced sleep, and impaired judgment — the manic pole of bipolar.","wiki":"bipolar","category":"disorder"},{"term":"maoi","aliases":["monoamine oxidase inhibitor","mao inhibitor","maois","mao-a","mao-b","maoi"],"def":"Monoamine oxidase inhibitor — a potent, reserved antidepressant needing a low-tyramine diet and drug washout intervals.","wiki":null,"category":"class"},{"term":"serotonin syndrome","aliases":["serotonergic toxicity","serotonin toxidrome","serotonin syndrome","serotonin toxicity","5-ht syndrome"],"def":"A potentially fatal excess of serotonin — agitation, autonomic instability, clonus and hyperreflexia (legs>arms), hyperthermia.","wiki":"serotonin-syndrome","category":"syndrome"},{"term":"cyp3a4","aliases":["cyp3a4"],"def":"A major liver and gut enzyme metabolizing many drugs; inducers cut levels, including reducing oral-contraceptive efficacy.","wiki":null,"category":"pharmacology"},{"term":"acute dystonia","aliases":["acute dystonic reaction","dystonic reaction","oculogyric crisis","acute dystonia","laryngospasm","torticollis","dystonia","dystonic"],"def":"Sudden sustained muscle spasm (neck, eyes, tongue) soon after a dopamine blocker; treated with IM/IV anticholinergics.","wiki":"eps","category":"adverse-effect"},{"term":"dystonia","aliases":["dystonic reaction","acute dystonia","dystonia"],"def":"Sustained involuntary muscle contractions causing twisting or abnormal postures; acute dystonia is an early antipsychotic reaction.","wiki":"eps","category":"adverse-effect"},{"term":"stimulant","aliases":["psychostimulant","stimulants","stimulant"],"def":"ADHD medications (methylphenidate, amphetamines) that raise dopamine and norepinephrine — first-line but controlled substances.","wiki":null,"category":"class"},{"term":"hyperprolactinemia","aliases":["hyperprolactinaemia","prolactin elevation","hyperprolactinemia","elevated prolactin","raised prolactin","high prolactin","prolactin"],"def":"Elevated blood prolactin from D2 blockade; causes galactorrhea, menstrual changes, gynecomastia and sexual dysfunction.","wiki":null,"category":"adverse-effect"},{"term":"delirium","aliases":["acute confusional state","hyperactive delirium","hypoactive delirium","acute confusion","encephalopathy","delirium"],"def":"An acute, fluctuating disturbance of attention and awareness from a medical cause; the hypoactive form is easily missed.","wiki":"delirium","category":"disorder"},{"term":"ceiling effect","aliases":["ceiling on respiratory depression","no ceiling effect","ceiling effect"],"def":"A dose above which more drug adds no extra effect; partial agonists like buprenorphine have one, barbiturates do not.","wiki":null,"category":"pharmacology"},{"term":"augmentation","aliases":["augmentation","adjunctive","augment","adjunct"],"def":"Adding a second agent (e.g., lithium or an atypical antipsychotic) to boost a partially effective antidepressant.","wiki":null,"category":"pharmacology"},{"term":"obsessive-compulsive disorder","aliases":["obsessive-compulsive disorder","obsessions and compulsions","compulsions","obsessions","ocd"],"def":"Intrusive, distressing obsessions and repetitive compulsions performed to relieve them; ritual relief is only fleeting.","wiki":"ocd","category":"disorder"},{"term":"panic attack","aliases":["unexpected panic","panic disorder","panic attacks","panic attack","panic"],"def":"A sudden surge of intense fear peaking within minutes, with somatic symptoms and fear of dying or losing control; recurrent unexpected attacks define panic disorder.","wiki":"panic","category":"disorder"},{"term":"respiratory depression","aliases":["respiratory depression and apnea","cardiorespiratory depression","respiratory depression"],"def":"Slowed, shallow breathing that can be fatal; risk rises sharply when opioids combine with benzodiazepines or alcohol.","wiki":null,"category":"adverse-effect"},{"term":"dementia","aliases":["major neurocognitive disorder","neurocognitive disorder","alzheimer's disease","lewy body dementia","alzheimer disease","alzheimer","dementia","bpsd"],"def":"A progressive, chronic decline in memory and cognition that impairs function; Alzheimer disease is the commonest cause.","wiki":"dementia","category":"disorder"},{"term":"depot","aliases":["long-acting injectable","depot injection","decanoate depot","decanoate","palmitate","depot"],"def":"A long-acting injectable antipsychotic that releases drug slowly over weeks, giving reliable levels and aiding adherence.","wiki":null,"category":"pharmacology"},{"term":"adhd","aliases":["attention-deficit/hyperactivity disorder","attention deficit hyperactivity disorder","attention deficit","adhd"],"def":"Developmentally excessive inattention, hyperactivity and impulsivity with childhood onset and cross-situational impairment.","wiki":"adhd","category":"disorder"},{"term":"titration","aliases":["uptitration","re-titrate","titration","titrating","titrated","titrate"],"def":"Gradually adjusting a drug's dose up or down to balance efficacy against tolerability; slow titration can be a safety measure (e.g., lamotrigine).","wiki":null,"category":"pharmacology"},{"term":"active metabolite","aliases":["active metabolites","active metabolite"],"def":"A pharmacologically active breakdown product of a drug that can prolong or add to its effects (e.g., nordiazepam from diazepam).","wiki":null,"category":"pharmacology"},{"term":"partial agonist","aliases":["partial agonist","partial agonism"],"def":"A drug that binds a receptor but activates it only partly, stabilizing signalling; e.g., aripiprazole, buprenorphine.","wiki":null,"category":"pharmacology"},{"term":"tremor","aliases":["essential tremor","resting tremor","tremor at rest","coarse tremor","fine tremor","tremors","tremor"],"def":"Rhythmic involuntary shaking; a fine tremor is common with lithium/SSRIs, while a coarse tremor suggests lithium toxicity.","wiki":null,"category":"sign"},{"term":"vmat2 inhibitor","aliases":["vmat2 inhibitors","vmat2 inhibitor","vmat2"],"def":"A drug that depletes presynaptic dopamine by blocking its vesicular transporter — used for tardive dyskinesia and chorea.","wiki":null,"category":"class"},{"term":"boxed warning","aliases":["class boxed warning","boxed abuse warning","black box warning","black-box warning","boxed warning"],"def":"The strongest safety warning a regulator can require on a drug label, flagging serious or life-threatening risks.","wiki":null,"category":"other"},{"term":"phenothiazine","aliases":["phenothiazines","phenothiazine"],"def":"A typical antipsychotic class (e.g., chlorpromazine, fluphenazine) where potency drives the EPS-versus-sedation trade-off.","wiki":null,"category":"class"},{"term":"reuptake inhibition","aliases":["reuptake inhibition","reuptake inhibitor","blocks reuptake","reuptake"],"def":"Blocking the transporter that clears a neurotransmitter from the synapse, raising its levels; the basis of SSRIs and SNRIs.","wiki":null,"category":"pharmacology"},{"term":"mood stabilizer","aliases":["mood stabilizers","mood stabilizer","mood stabiliser"],"def":"A drug that prevents manic and depressive relapse in bipolar disorder (lithium, valproate, lamotrigine).","wiki":null,"category":"class"},{"term":"taper","aliases":["slow taper","tapering","tapered"],"def":"Gradual dose reduction to avoid withdrawal, rebound or seizures when stopping a drug.","wiki":null,"category":"pharmacology"},{"term":"neuroleptic malignant syndrome","aliases":["neuroleptic malignant syndrome","nms"],"def":"A rare, life-threatening dopamine-blocker reaction: fever, lead-pipe rigidity, autonomic instability, and very high CK.","wiki":"nms","category":"syndrome"},{"term":"cyp2d6","aliases":["cyp2d6"],"def":"A liver enzyme metabolizing many psychotropics; inhibitors (paroxetine, fluoxetine, bupropion) raise substrate levels.","wiki":null,"category":"pharmacology"},{"term":"ptsd","aliases":["post-traumatic stress disorder","posttraumatic stress disorder","posttraumatic stress","hyperarousal","ptsd"],"def":"Intrusive re-experiencing, avoidance, negative mood, and hyperarousal lasting over a month after a traumatic event.","wiki":"ptsd","category":"disorder"},{"term":"lead-pipe rigidity","aliases":["generalised rigidity","generalized rigidity","lead-pipe rigidity","muscle rigidity","rigidity"],"def":"Uniform, sustained muscle stiffness throughout the range of motion — the classic rigidity of neuroleptic malignant syndrome.","wiki":"nms","category":"sign"},{"term":"qt prolongation","aliases":["torsades de pointes","qtc prolongation","qt prolongation","qt prolonging","qt-prolonging","prolonged qt","qt interval","torsades","long qt","qtc"],"def":"Lengthening of the heart's QT interval on ECG, raising the risk of the arrhythmia torsades de pointes and sudden death.","wiki":null,"category":"adverse-effect"},{"term":"rigidity","aliases":["lead-pipe rigidity","cogwheel rigidity","muscle rigidity","rigidity","rigid"],"def":"Increased muscle tone; lead-pipe rigidity is a hallmark of NMS, while cogwheel rigidity marks drug-induced parkinsonism.","wiki":null,"category":"sign"},{"term":"decanoate","aliases":["decanoate depot","decanoate"],"def":"An oily ester formulation of an antipsychotic that dissolves slowly from muscle to give a long-acting depot injection.","wiki":null,"category":"pharmacology"},{"term":"enantiomer","aliases":["single enantiomer","s-enantiomer","r-enantiomer","d-enantiomer","enantiomers","enantiomer","l-isomer","racemate","racemic","isomer"],"def":"One of two mirror-image forms of a molecule; escitalopram and dexamphetamine are marketed as single active enantiomers.","wiki":null,"category":"pharmacology"},{"term":"orthostatic hypotension","aliases":["orthostatic hypotension","first-dose hypotension","orthostatic dizziness","postural hypotension","orthostatic syncope","orthostasis","orthostatic"],"def":"A blood-pressure drop on standing causing dizziness or fainting — common with alpha-1 blockade and many psychotropics.","wiki":null,"category":"adverse-effect"},{"term":"treatment-resistant depression","aliases":["treatment-resistant depression","treatment resistant depression","refractory depression","resistant depression","treatment-resistant"],"def":"Depression that fails to respond to two or more adequate antidepressant trials; options include esketamine and ECT.","wiki":"mdd","category":"disorder"},{"term":"agranulocytosis","aliases":["severe neutropenia","agranulocytosis","neutropenia"],"def":"A dangerous fall in neutrophils (ANC under ~500) leaving the patient prone to serious infection; the key clozapine risk.","wiki":null,"category":"adverse-effect"},{"term":"generalized anxiety disorder","aliases":["generalized anxiety disorder","generalised anxiety disorder","generalized anxiety","generalised anxiety","gad"],"def":"Persistent, excessive worry across many life domains for months, with restlessness, tension, and trouble controlling the worry.","wiki":"gad","category":"disorder"},{"term":"snri","aliases":["serotonin-norepinephrine reuptake inhibitor","snris","snri"],"def":"Serotonin-norepinephrine reuptake inhibitor (e.g., venlafaxine, duloxetine); adds noradrenergic action and can raise BP.","wiki":null,"category":"class"},{"term":"washout","aliases":["washout period","washout"],"def":"A drug-free interval before starting an interacting agent — e.g., 14 days around an MAOI, up to 5 weeks after fluoxetine.","wiki":null,"category":"pharmacology"},{"term":"cyp1a2","aliases":["cyp1a2"],"def":"A liver enzyme inhibited by fluvoxamine and induced by cigarette smoke that clears drugs like duloxetine and clozapine.","wiki":null,"category":"pharmacology"},{"term":"anticholinergic toxicity","aliases":["anticholinergic toxidrome","anticholinergic toxicity","anticholinergic delirium","antimuscarinic toxicity","anticholinergic burden"],"def":"Muscarinic blockade causing dry flushed skin, dilated pupils, urinary retention, and delirium — 'hot, dry, red, and mad'.","wiki":"anticholinergic-toxicity","category":"syndrome"},{"term":"torsades de pointes","aliases":["torsades de pointes","torsades","torsade"],"def":"A polymorphic ventricular tachycardia triggered by a prolonged QT interval; can degenerate into fatal arrhythmia.","wiki":null,"category":"adverse-effect"},{"term":"clonus","aliases":["inducible clonus","ocular clonus","ankle clonus","clonus","clonic"],"def":"Rhythmic involuntary muscle contractions on stretch; inducible or spontaneous clonus is a key serotonin-syndrome sign.","wiki":null,"category":"sign"},{"term":"sexual dysfunction","aliases":["sexual side effects","sexual dysfunction","decreased libido","reduced libido","anorgasmia"],"def":"Impaired libido, arousal or orgasm; a common serotonergic (SSRI/clomipramine) side effect and often the main complaint.","wiki":null,"category":"adverse-effect"},{"term":"bradycardia","aliases":["slowed heart rate","bradycardia","bradycardic"],"def":"Abnormally slow heart rate; a risk with alpha-2 agonists (clonidine, dexmedetomidine) and cholinesterase inhibitors.","wiki":null,"category":"sign"},{"term":"craving","aliases":["cravings","craving"],"def":"A strong urge to use a substance; a target of relapse-prevention drugs such as naltrexone, acamprosate and varenicline.","wiki":null,"category":"symptom"},{"term":"glucuronidation","aliases":["glucuronidation","glucuronidated"],"def":"A liver conjugation pathway (not CYP) that clears lorazepam, oxazepam, and temazepam — preferred in liver disease.","wiki":null,"category":"pharmacology"},{"term":"first-generation antipsychotic","aliases":["first-generation antipsychotic","typical antipsychotic","neuroleptic","fgas","fga"],"def":"A 'typical' antipsychotic (e.g., haloperidol): a potent dopamine (D2) blocker with high EPS and prolactin-elevating potential.","wiki":null,"category":"class"},{"term":"second-generation antipsychotic","aliases":["second-generation antipsychotic","atypical antipsychotic","sgas","sga"],"def":"Second-generation (atypical) antipsychotics — 5-HT2A/D2 blockers with lower EPS but more metabolic risk than older agents.","wiki":null,"category":"class"},{"term":"anticonvulsant","aliases":["anticonvulsants","anticonvulsant","antiepileptic"],"def":"A seizure-suppressing drug; several (valproate, carbamazepine, lamotrigine) double as mood stabilizers.","wiki":null,"category":"class"},{"term":"d2 antagonist","aliases":["dopamine antagonist","d2 antagonist","d2 antagonism","d2 blockade"],"def":"Blockade of dopamine D2 receptors, the core antipsychotic mechanism and the source of EPS and prolactin elevation.","wiki":null,"category":"pharmacology"},{"term":"d2 blockade","aliases":["dopamine blockade","d2 antagonism","d2 blockade","d2 blocker"],"def":"Blockade of dopamine D2 receptors — the core antipsychotic action, which also drives EPS and prolactin elevation.","wiki":null,"category":"pharmacology"},{"term":"hyperthermia","aliases":["hyperthermia","hyperthermic"],"def":"Dangerously high body temperature; a life-threatening feature of serotonin syndrome and neuroleptic malignant syndrome.","wiki":null,"category":"sign"},{"term":"prn","aliases":["prn"],"def":"'As needed' dosing — a medication taken only when symptoms occur rather than on a fixed schedule.","wiki":null,"category":"other"},{"term":"prodrug","aliases":["prodrug"],"def":"An inactive drug the body converts into its active form (e.g. lisdexamfetamine), which can lower misuse potential.","wiki":null,"category":"pharmacology"},{"term":"cholinesterase inhibitor","aliases":["acetylcholinesterase inhibitor","cholinesterase inhibitors","cholinesterase inhibitor","ache inhibitor","chei"],"def":"A drug that blocks acetylcholine breakdown to boost cholinergic signalling; used symptomatically in Alzheimer dementia.","wiki":null,"category":"class"},{"term":"antihistamine","aliases":["first-generation antihistamine","antihistaminergic","h1 antihistamine","antihistamines","antihistaminic","antihistamine","h1 antagonist","h1 blockade","h1 blocker"],"def":"An H1-receptor blocker whose sedating effect underlies hypnotic and anxiolytic uses (hydroxyzine, doxepin, mirtazapine).","wiki":null,"category":"class"},{"term":"hepatotoxicity","aliases":["drug-induced liver injury","hepatotoxicity","liver toxicity","liver injury","hepatotoxic"],"def":"Drug-induced liver damage — a concern with duloxetine, valproate, and phenelzine; watch for jaundice and rising LFTs.","wiki":null,"category":"adverse-effect"},{"term":"sublingual","aliases":["sublingual"],"def":"Given under the tongue to absorb directly into blood, bypassing first-pass metabolism (e.g. asenapine, buprenorphine).","wiki":null,"category":"pharmacology"},{"term":"social anxiety disorder","aliases":["social anxiety disorder","performance anxiety","social anxiety","social phobia","stage fright"],"def":"A marked, persistent fear of scrutiny or embarrassment in social or performance situations, leading to dread or avoidance.","wiki":"social-anxiety","category":"disorder"},{"term":"tachycardia","aliases":["tachycardia","tachycardic"],"def":"Abnormally fast heart rate; seen in anticholinergic toxicity, stimulant use, and withdrawal states.","wiki":null,"category":"sign"},{"term":"stevens-johnson syndrome","aliases":["toxic epidermal necrolysis","stevens-johnson syndrome","stevens–johnson syndrome","stevens johnson syndrome","sjs/ten","sjs"],"def":"A life-threatening blistering reaction of skin and mucosa; a slow-titration concern for lamotrigine and carbamazepine.","wiki":null,"category":"adverse-effect"},{"term":"urinary retention","aliases":["urinary retention","urinary hesitancy"],"def":"Difficulty emptying the bladder; part of the anticholinergic toxidrome ('full as a flask') and a noradrenergic effect.","wiki":null,"category":"adverse-effect"},{"term":"abuse potential","aliases":["misuse potential","abuse potential","diversion"],"def":"The likelihood a medication is misused or diverted for non-medical use; high for stimulants and short-acting, high-potency benzodiazepines.","wiki":null,"category":"other"},{"term":"gaba-a receptor","aliases":["gaba-a receptor","gaba-a","gaba a"],"def":"The brain's main inhibitory receptor — a chloride channel that benzodiazepines and barbiturates enhance to calm neural activity.","wiki":null,"category":"pharmacology"},{"term":"hallucination","aliases":["auditory hallucinations","visual hallucinations","hallucinations","hallucination","hallucinating"],"def":"A false sensory perception (often visual or auditory) occurring without a real stimulus; a core psychotic symptom.","wiki":null,"category":"symptom"},{"term":"hyponatremia","aliases":["low serum sodium","hyponatraemia","hyponatremia","low sodium","siadh"],"def":"Low serum sodium; SSRIs/SNRIs can cause it via SIADH (especially in older women), producing confusion, unsteadiness and falls.","wiki":null,"category":"adverse-effect"},{"term":"tyramine crisis","aliases":["hypertensive emergency","hypertensive crisis","tyramine reaction","tyramine crisis","cheese reaction"],"def":"A hypertensive crisis when tyramine-rich foods (aged cheese, cured meats, draught beer) are eaten on an irreversible MAOI.","wiki":"tyramine-crisis","category":"syndrome"},{"term":"diaphoresis","aliases":["profuse sweating","diaphoresis","diaphoretic","sweating"],"def":"Excessive sweating; a feature of autonomic instability in serotonin syndrome, NMS, and alcohol or opioid withdrawal.","wiki":null,"category":"sign"},{"term":"hyperreflexia","aliases":["brisk hyperreflexia","brisk reflexes","hyperreflexia","hyperreflexic"],"def":"Exaggerated, brisk deep-tendon reflexes; a hallmark of serotonin syndrome, in contrast to the hyporeflexia of NMS.","wiki":null,"category":"sign"},{"term":"seizure threshold","aliases":["lowers the seizure threshold","lowered seizure threshold","seizure threshold"],"def":"The brain's susceptibility to seizures; some drugs (bupropion, clozapine, high-dose TCAs) lower it, raising seizure risk.","wiki":null,"category":"pharmacology"},{"term":"enzyme inducer","aliases":["enzyme induction","enzyme inducer","cyp3a4 inducer","potent inducer","cyp induction","cyp inducer","3a4 inducer","inducer"],"def":"A drug that speeds liver enzymes so co-medications clear faster and drop in level, e.g., carbamazepine or phenobarbital.","wiki":null,"category":"pharmacology"},{"term":"enzyme induction","aliases":["enzyme induction","auto-induction","cyp3a4 inducer","induces cyp3a4","enzyme inducer","cyp induction","autoinduction","cyp inducer","inducer"],"def":"When a drug speeds up metabolic enzymes, lowering levels of itself or co-prescribed drugs (e.g., contraceptive failure).","wiki":null,"category":"pharmacology"},{"term":"tolerance","aliases":["tolerance"],"def":"Needing more drug over time for the same effect; it is lost after a break, so agents like clozapine are restarted low.","wiki":null,"category":"pharmacology"},{"term":"z-drug","aliases":["benzo-site hypnotic","z-drugs","z-drug","z drug"],"def":"Non-benzodiazepine hypnotics (zopiclone, zolpidem) acting at the benzodiazepine GABA-A site, used short-term for insomnia.","wiki":null,"category":"class"},{"term":"nmda antagonist","aliases":["nmda-receptor antagonist","nmda receptor antagonist","nmda antagonist","nmda antagonism","nmda-antagonist","nmda blockade","nmda blocker"],"def":"A drug blocking the glutamate NMDA receptor; memantine (dementia) and ketamine/esketamine (depression) work this way.","wiki":null,"category":"pharmacology"},{"term":"alcohol use disorder","aliases":["alcohol use disorder","alcohol withdrawal","alcohol dependence","alcoholism","aud"],"def":"A chronic, relapsing pattern of compulsive alcohol use with tolerance, withdrawal, and impaired control despite harm.","wiki":"aud","category":"disorder"},{"term":"beta-blocker","aliases":["beta-adrenergic antagonist","beta antagonist","beta-blockade","beta blockade","beta-blocker","beta blocker","betablocker","β-blocker"],"def":"A beta-adrenergic antagonist; propranolol treats akathisia, tremor and performance anxiety but can trigger bronchospasm.","wiki":null,"category":"class"},{"term":"lfts","aliases":["liver function tests","lfts"],"def":"Liver function tests — blood markers (ALT, AST) followed to detect drug-induced liver injury.","wiki":null,"category":"lab"},{"term":"lithium toxicity","aliases":["high lithium level","lithium poisoning","lithium toxicity","lithium overdose"],"def":"Coarse tremor, ataxia, slurred speech, and confusion from a high lithium level — a narrow-index emergency; check the level.","wiki":"lithium-toxicity","category":"syndrome"},{"term":"opioid agonist therapy","aliases":["opioid agonist treatment","opioid agonist therapy","oat"],"def":"Maintenance treatment of opioid use disorder with methadone or buprenorphine/naloxone to reduce craving and overdose risk.","wiki":"oud","category":"other"},{"term":"teratogen","aliases":["teratogenicity","teratogenic","teratogen"],"def":"A substance that causes fetal malformation; valproate is the worst mood stabilizer (neural-tube defects, lower childhood IQ).","wiki":null,"category":"pharmacology"},{"term":"tourette syndrome","aliases":["tourette syndrome","tourette's","motor tics","tourette","tics"],"def":"A neurodevelopmental disorder of multiple motor and vocal tics beginning in childhood.","wiki":null,"category":"disorder"},{"term":"alcohol withdrawal","aliases":["alcohol withdrawal","delirium tremens","dts"],"def":"Tremor, anxiety, and autonomic arousal after stopping heavy drinking; severe cases progress to seizures or delirium tremens.","wiki":"aud","category":"syndrome"},{"term":"discontinuation syndrome","aliases":["antidepressant discontinuation syndrome","antidepressant discontinuation","antidepressant withdrawal","discontinuation syndrome","ssri discontinuation","ssri withdrawal","finish syndrome","brain zaps"],"def":"Flu-like malaise, dizziness, and electric-shock 'brain zaps' after abruptly stopping a short-half-life antidepressant.","wiki":"discontinuation-syndrome","category":"syndrome"},{"term":"tobacco use disorder","aliases":["tobacco use disorder","nicotine dependence","smoking cessation","quit smoking","tud"],"def":"Nicotine dependence with compulsive tobacco use and withdrawal; pharmacotherapy plus counselling roughly triples quit rates.","wiki":"tud","category":"disorder"},{"term":"amnesia","aliases":["anterograde amnesia","memory gaps","memory loss","amnestic","amnesia"],"def":"Inability to form new memories over a period — a known effect of benzodiazepines and Z-drugs, especially short-acting ones.","wiki":null,"category":"adverse-effect"},{"term":"ataxia","aliases":["incoordination","unsteady gait","unsteadiness","ataxia","ataxic"],"def":"Loss of coordinated movement and unsteady gait; here a sign of lithium toxicity or benzodiazepine excess.","wiki":null,"category":"sign"},{"term":"diversion","aliases":["diversion","diverted"],"def":"Redirecting a prescribed controlled drug to non-medical use or sale; a risk with stimulants and some anticholinergics.","wiki":null,"category":"other"},{"term":"neuropathic pain","aliases":["diabetic peripheral neuropathic pain","diabetic peripheral neuropathy","peripheral neuropathy","diabetic neuropathy","neuropathic pain","neuropathy"],"def":"Pain from nerve damage or dysfunction (e.g. diabetic neuropathy), often responsive to SNRIs, TCAs, or gabapentinoids.","wiki":null,"category":"disorder"},{"term":"perinatal depression","aliases":["perinatal mood and anxiety disorders","postpartum depression","perinatal depression","ppd"],"def":"A mood or anxiety disorder in pregnancy or the year after birth; treatment balances maternal illness against fetal/infant exposure.","wiki":"perinatal","category":"disorder"},{"term":"postpartum depression","aliases":["postpartum depression","peripartum depression","perinatal depression","postnatal depression","postpartum anxiety","ppd"],"def":"Depression during pregnancy or after childbirth; treated with the best-studied agents at the lowest effective dose.","wiki":"perinatal","category":"disorder"},{"term":"acute angle-closure glaucoma","aliases":["acute angle-closure glaucoma","angle-closure glaucoma","glaucoma"],"def":"A sudden painful rise in eye pressure threatening vision; an idiosyncratic topiramate reaction, usually in the first month.","wiki":null,"category":"adverse-effect"},{"term":"angle-closure glaucoma","aliases":["acute angle-closure glaucoma","angle-closure glaucoma","narrow-angle glaucoma","acute angle-closure","angle closure","angle-closure","glaucoma"],"def":"A sudden rise in eye pressure damaging the optic nerve; topiramate can precipitate it with eye pain and blurred vision.","wiki":null,"category":"adverse-effect"},{"term":"bronchospasm","aliases":["bronchospasm"],"def":"Sudden airway constriction causing wheeze and breathlessness; non-selective beta-blockers can trigger it in asthma or COPD.","wiki":null,"category":"adverse-effect"},{"term":"narcolepsy","aliases":["narcoleptic","narcolepsy"],"def":"A chronic disorder of excessive daytime sleepiness with abnormal REM intrusion, caused by deficiency of wake-promoting orexin.","wiki":null,"category":"disorder"},{"term":"rima","aliases":["reversible inhibitor of monoamine oxidase a","reversible inhibitor of mao-a","reversible maoi","rima"],"def":"A reversible MAO-A inhibitor (moclobemide) that tyramine can displace, so no strict diet — but serotonin cautions remain.","wiki":null,"category":"class"},{"term":"syncope","aliases":["fainting","syncope"],"def":"A transient loss of consciousness from a brief fall in blood flow to the brain (fainting).","wiki":null,"category":"sign"},{"term":"anc","aliases":["absolute neutrophil count","neutrophil count","anc"],"def":"The count of infection-fighting neutrophils in blood; tracked on clozapine, with strict thresholds to hold or stop the drug.","wiki":null,"category":"lab"},{"term":"controlled substance","aliases":["controlled substance","controlled-substance","schedule iv"],"def":"A drug with legally restricted prescribing due to abuse or dependence potential, e.g., stimulants and benzodiazepines.","wiki":null,"category":"other"},{"term":"delusion","aliases":["mood-congruent delusions","delusional","delusions","delusion"],"def":"A fixed false belief firmly held despite clear contrary evidence; a core feature of psychosis.","wiki":null,"category":"symptom"},{"term":"full agonist","aliases":["mu-opioid agonist","full agonist"],"def":"A drug that fully activates a receptor; at the mu-opioid receptor this means no ceiling on respiratory depression (e.g. methadone).","wiki":null,"category":"pharmacology"},{"term":"loading dose","aliases":["loading dose"],"def":"A large initial dose given to reach a therapeutic level quickly; valproate can be loaded for acute mania.","wiki":null,"category":"pharmacology"},{"term":"priapism","aliases":["priapism"],"def":"A prolonged, often painful erection unrelated to arousal; a urologic emergency linked to alpha-1 blockers like trazodone.","wiki":null,"category":"adverse-effect"},{"term":"resting tremor","aliases":["resting tremor","coarse tremor"],"def":"Rhythmic shaking present at rest that eases with movement — typical of parkinsonism; a coarse tremor also flags lithium toxicity.","wiki":null,"category":"sign"},{"term":"hla-b*1502","aliases":["hla-b*1502","hla-b 1502","hla-b1502"],"def":"A genetic allele (common in some Asian ancestries) screened before carbamazepine because it raises Stevens-Johnson risk.","wiki":null,"category":"lab"},{"term":"myocarditis","aliases":["myocarditis"],"def":"Inflammation of the heart muscle (fever, chest pain, rising troponin/CRP) that clusters in the first weeks of clozapine.","wiki":null,"category":"adverse-effect"},{"term":"parkinson disease psychosis","aliases":["parkinson disease psychosis","parkinson-disease psychosis","parkinson's psychosis","pd psychosis","pdp"],"def":"Visual hallucinations and delusions in Parkinson disease; treated without worsening motor function (e.g., pimavanserin).","wiki":"pd-psychosis","category":"disorder"},{"term":"rebound hypertension","aliases":["rebound hypertension","rebound htn"],"def":"A surge in blood pressure after abruptly stopping a central alpha-2 agonist (clonidine, guanfacine); taper to avoid it.","wiki":null,"category":"adverse-effect"},{"term":"status epilepticus","aliases":["status epilepticus"],"def":"A prolonged or repeated seizure without recovery of consciousness — a neurologic emergency; IV lorazepam is first-line.","wiki":null,"category":"disorder"},{"term":"trough level","aliases":["therapeutic drug level","trough level","12-h trough","serum level","trough"],"def":"A drug level drawn just before the next dose (its lowest point); used to monitor lithium and other narrow-index drugs.","wiki":null,"category":"lab"},{"term":"ebstein anomaly","aliases":["cardiac malformation","ebstein's anomaly","ebstein anomaly","ebstein"],"def":"A congenital malformation of the heart's tricuspid valve; a small first-trimester risk associated with lithium exposure.","wiki":null,"category":"other"},{"term":"neural-tube defect","aliases":["neural-tube defects","neural tube defects","neural-tube defect","neural tube defect","spina bifida","ntds"],"def":"Serious congenital malformations of the brain or spine (e.g. spina bifida) linked to valproate exposure in pregnancy.","wiki":null,"category":"other"},{"term":"neuroactive steroid","aliases":["neuroactive steroids","neuroactive steroid","neurosteroid"],"def":"A steroid that modulates GABA-A receptors; brexanolone and zuranolone use this mechanism for postpartum depression.","wiki":null,"category":"class"},{"term":"neurosteroid","aliases":["neuroactive steroid","gaba-a neurosteroid","allopregnanolone","neurosteroids","neurosteroid"],"def":"A steroid that acts on brain GABA-A receptors; brexanolone and zuranolone are neurosteroids for postpartum depression.","wiki":null,"category":"pharmacology"},{"term":"opioid use disorder","aliases":["opioid use disorder","opioid withdrawal","opioid dependence","opioid addiction","opioid overdose","oud"],"def":"Compulsive opioid use despite harm; first-line treatment is opioid agonist therapy (buprenorphine/naloxone or methadone).","wiki":"oud","category":"disorder"},{"term":"precipitated withdrawal","aliases":["precipitated opioid withdrawal","precipitated withdrawal","precipitates withdrawal","precipitated-withdrawal","opioid withdrawal"],"def":"Abrupt, severe opioid withdrawal triggered by giving buprenorphine or naltrexone before the patient is already in withdrawal.","wiki":"oud","category":"adverse-effect"},{"term":"thioxanthene","aliases":["thioxanthenes","thioxanthene"],"def":"A first-generation antipsychotic class (zuclopenthixol, flupenthixol) available in Canada, including as depots.","wiki":null,"category":"class"},{"term":"5-ht2a inverse agonist","aliases":["5-ht2a inverse agonist","inverse agonist"],"def":"A drug that turns down constitutive 5-HT2A receptor signalling; pimavanserin is a selective 5-HT2A inverse agonist for Parkinson psychosis.","wiki":null,"category":"pharmacology"},{"term":"bulimia nervosa","aliases":["bulimia nervosa","bulimia"],"def":"An eating disorder of binge eating with compensatory purging; bupropion is contraindicated because of seizure risk.","wiki":null,"category":"disorder"},{"term":"enuresis","aliases":["nocturnal enuresis","bed-wetting","bedwetting","enuresis"],"def":"Involuntary night-time bed-wetting; imipramine is a recognised second-line option in children.","wiki":null,"category":"disorder"},{"term":"extended-release","aliases":["controlled-release","sustained-release","extended-release","extended release","oros"],"def":"A formulation that releases drug slowly for once-daily, all-day coverage with smoother levels and fewer peaks and troughs.","wiki":null,"category":"pharmacology"},{"term":"inverse agonist","aliases":["inverse agonist"],"def":"A drug that binds a receptor and produces the opposite effect to an agonist; pimavanserin is a 5-HT2A inverse agonist.","wiki":null,"category":"pharmacology"},{"term":"metabolic syndrome","aliases":["antipsychotic weight gain","metabolic side effects","metabolic syndrome","metabolic burden","metabolic risk"],"def":"A cluster of weight gain, high glucose, and dyslipidemia — a key antipsychotic risk, worst with olanzapine and clozapine.","wiki":"metabolic-syndrome","category":"syndrome"},{"term":"reuptake inhibitor","aliases":["reuptake inhibition","reuptake inhibitor","reuptake blockade","reuptake blocker","blocks reuptake","reuptake block"],"def":"A drug that blocks reabsorption of a neurotransmitter, raising its level in the synapse — e.g. SSRIs block serotonin reuptake.","wiki":null,"category":"pharmacology"},{"term":"tetracyclic","aliases":["tetracyclic"],"def":"A four-ringed antidepressant such as maprotiline or mirtazapine.","wiki":null,"category":"class"},{"term":"treatment-resistant schizophrenia","aliases":["treatment-resistant schizophrenia","treatment resistant schizophrenia"],"def":"Schizophrenia failing two or more adequate antipsychotic trials; clozapine is the only agent with proven superior efficacy.","wiki":"schizophrenia","category":"disorder"},{"term":"butyrophenone","aliases":["butyrophenones","butyrophenone"],"def":"A high-potency first-generation antipsychotic class (haloperidol, droperidol) with strong D2 blockade and prominent EPS.","wiki":null,"category":"class"},{"term":"complex sleep behaviours","aliases":["complex sleep behaviours","complex sleep behaviors","complex sleep behaviour","sleep-driving","sleep-walking","sleep-eating"],"def":"Sleep-walking, sleep-driving, or sleep-eating with no memory of it — linked to Z-drugs (a boxed warning for zolpidem).","wiki":null,"category":"adverse-effect"},{"term":"cyp2c19","aliases":["cyp2c19","2c19"],"def":"A liver enzyme with poor-metabolizer variants; relevant to citalopram/escitalopram dose caps and clobazam clearance.","wiki":null,"category":"pharmacology"},{"term":"flushing","aliases":["flushed skin","flushing"],"def":"Reddening and warmth of the skin; a hallmark of the disulfiram-alcohol reaction and of anticholinergic toxicity.","wiki":null,"category":"sign"},{"term":"poor metabolizer","aliases":["poor metabolizers","poor metabolizer","poor metaboliser"],"def":"Someone whose genetic enzyme variant clears a drug slowly, so standard doses produce higher-than-expected levels.","wiki":null,"category":"pharmacology"},{"term":"sympathomimetic","aliases":["sympathomimetics","sympathomimetic"],"def":"A drug mimicking adrenaline (e.g., pseudoephedrine); dangerous with MAOIs, which can trigger a hypertensive crisis.","wiki":null,"category":"pharmacology"},{"term":"autonomic instability","aliases":["autonomic instability"],"def":"Dangerous swings in heart rate, blood pressure, and temperature; a feature of NMS, serotonin syndrome, and delirium tremens.","wiki":null,"category":"sign"},{"term":"catatonia","aliases":["malignant catatonia","catatonic features","waxy flexibility","catatonia","catatonic"],"def":"A syndrome of abnormal movement and reactivity — immobility, mutism, rigidity, or excitement; severe cases may need ECT.","wiki":null,"category":"syndrome"},{"term":"ileus","aliases":["bowel obstruction","paralytic ileus","ileus"],"def":"Loss of bowel motility causing obstruction; severe clozapine-induced constipation can progress to this.","wiki":null,"category":"adverse-effect"},{"term":"linear kinetics","aliases":["linear kinetics"],"def":"Predictable dosing where blood levels rise in proportion to the dose (e.g., pregabalin), unlike gabapentin's saturable absorption.","wiki":null,"category":"pharmacology"},{"term":"nonlinear kinetics","aliases":["saturable absorption","nonlinear kinetics","linear kinetics"],"def":"Linear kinetics make drug levels dose-proportional and predictable; nonlinear/saturable absorption (gabapentin) means bioavailability falls as dose rises.","wiki":null,"category":"pharmacology"},{"term":"peripheral edema","aliases":["peripheral edema","swollen ankles","ankle edema","oedema","edema"],"def":"Tissue swelling from fluid; ankle edema is a tell of amantadine, and alpha-2-delta ligands (gabapentin, pregabalin) cause peripheral edema.","wiki":null,"category":"adverse-effect"},{"term":"photosensitivity","aliases":["photosensitivity"],"def":"Heightened skin sensitivity to sunlight causing easy sunburn; classic with chlorpromazine — counsel sun protection.","wiki":null,"category":"adverse-effect"},{"term":"withdrawal seizures","aliases":["withdrawal seizures"],"def":"Seizures on abruptly stopping a sedative (benzodiazepine, barbiturate, alcohol) — a key reason to taper rather than stop suddenly.","wiki":null,"category":"adverse-effect"},{"term":"autoinduction","aliases":["auto-induction","self-induction","autoinduction","autoinducing","autoinducer","autoinduces"],"def":"When a drug speeds up its own metabolism over the first weeks, so its level falls and must be rechecked (carbamazepine).","wiki":null,"category":"pharmacology"},{"term":"bioavailability","aliases":["bioavailability"],"def":"The fraction of a dose that reaches the bloodstream unchanged; reduced by first-pass metabolism or, for lurasidone, taking it without food.","wiki":null,"category":"pharmacology"},{"term":"cholestatic jaundice","aliases":["cholestatic jaundice","cholestasis"],"def":"Jaundice from impaired bile flow; a classic phenothiazine (e.g., chlorpromazine) adverse effect.","wiki":null,"category":"adverse-effect"},{"term":"chorea","aliases":["choreoathetoid movements","huntington chorea","choreoathetoid","choreiform","choreic","chorea"],"def":"Irregular, flowing involuntary movements; VMAT2 inhibitors treat chorea in Huntington disease and tardive dyskinesia.","wiki":null,"category":"sign"},{"term":"diabetic neuropathy","aliases":["painful diabetic neuropathy","diabetic neuropathy"],"def":"Nerve damage from diabetes causing burning, painful feet/hands; treated with duloxetine, TCAs or pregabalin.","wiki":null,"category":"other"},{"term":"enzyme inhibitor","aliases":["enzyme inhibition","enzyme inhibitor","cyp1a2 inhibitor","cyp inhibitor","3a4 inhibitor","2d6 inhibitor"],"def":"A drug that blocks metabolizing enzymes, raising co-drug levels (e.g. valproate slowing lamotrigine's clearance).","wiki":null,"category":"pharmacology"},{"term":"fibromyalgia","aliases":["fibromyalgia"],"def":"A chronic widespread-pain syndrome with fatigue and sleep disturbance; duloxetine and milnacipran are used.","wiki":null,"category":"disorder"},{"term":"huntington chorea","aliases":["huntington's chorea","huntington disease","huntington chorea"],"def":"An inherited neurodegenerative disease with involuntary dance-like movements (chorea) and cognitive decline.","wiki":null,"category":"disorder"},{"term":"hyporeflexia","aliases":["hyporeflexia","hyporeflexic"],"def":"Reduced or absent reflexes — seen in NMS, contrasting with the hyperreflexia of serotonin syndrome.","wiki":null,"category":"sign"},{"term":"intrinsic activity","aliases":["intrinsic activity"],"def":"How strongly a drug activates a receptor once bound; lower intrinsic activity at D2 (brexpiprazole) means less activation than aripiprazole.","wiki":null,"category":"pharmacology"},{"term":"mydriasis","aliases":["pupillary dilation","dilated pupils","mydriasis","mydriatic"],"def":"Pupil dilation; here a sign of opioid withdrawal (pinpoint pupils instead point to opioid intoxication).","wiki":null,"category":"sign"},{"term":"negative symptoms","aliases":["negative symptoms","negative features","negative symptom"],"def":"The 'taken-away' features of schizophrenia — blunted emotion, reduced speech, social withdrawal and loss of drive.","wiki":"schizophrenia","category":"symptom"},{"term":"nri","aliases":["selective norepinephrine reuptake inhibitor","norepinephrine reuptake inhibitor","nri"],"def":"A selective norepinephrine reuptake inhibitor (atomoxetine); a non-controlled ADHD option with delayed 2-4 week onset.","wiki":null,"category":"class"},{"term":"oculogyric crisis","aliases":["oculogyric crisis","oculogyric"],"def":"An acute dystonic reaction with forced, sustained upward deviation of the eyes; treated urgently with anticholinergics.","wiki":"eps","category":"adverse-effect"},{"term":"opioid withdrawal","aliases":["objective withdrawal","opioid withdrawal","opiate withdrawal"],"def":"Uncomfortable but rarely dangerous syndrome — anxiety, sweating, GI upset, myalgia, dilated pupils — on stopping opioids.","wiki":"oud","category":"syndrome"},{"term":"siadh","aliases":["syndrome of inappropriate antidiuretic hormone","syndrome of inappropriate adh","inappropriate adh","siadh"],"def":"Inappropriate ADH release causing water retention and dilutional hyponatremia; an SSRI and carbamazepine adverse effect.","wiki":null,"category":"syndrome"},{"term":"barbiturate","aliases":["barbiturates","barbiturate"],"def":"Older GABA-A sedatives (e.g., phenobarbital) with a narrow safety margin, high overdose lethality, and dangerous withdrawal.","wiki":null,"category":"class"},{"term":"cbc","aliases":["complete blood count","cbc"],"def":"Complete blood count — screens for agranulocytosis, neutropenia, and anemia.","wiki":null,"category":"lab"},{"term":"cbt-i","aliases":["cbt-i","cbti"],"def":"Cognitive behavioral therapy for insomnia — the durable first-line treatment (stimulus control, sleep restriction).","wiki":null,"category":"other"},{"term":"cows","aliases":["clinical opiate withdrawal scale"],"def":"The Clinical Opiate Withdrawal Scale; buprenorphine induction waits until it shows objective withdrawal (~8-12).","wiki":null,"category":"lab"},{"term":"dora","aliases":["dual orexin receptor antagonist","orexin receptor antagonist","orexin antagonist","orexin-blocker","doras","dora"],"def":"Dual orexin receptor antagonist (lemborexant) — blocks the brain's wake signal to promote sleep without dependence.","wiki":null,"category":"class"},{"term":"ect","aliases":["electroconvulsive therapy","ect"],"def":"Inducing a brief therapeutic seizure under anesthesia; a leading option for severe, psychotic, or emergency depression.","wiki":null,"category":"other"},{"term":"first-pass metabolism","aliases":["first-pass metabolism","first pass metabolism","first-pass effect","first-pass","first pass"],"def":"Metabolism of an oral drug by the gut and liver before it reaches the circulation, reducing how much active drug gets in.","wiki":null,"category":"pharmacology"},{"term":"galactorrhea","aliases":["galactorrhoea","galactorrhea"],"def":"Inappropriate milk discharge from the breast, driven by high prolactin (e.g. from D2-blocking antipsychotics).","wiki":null,"category":"sign"},{"term":"impulse-control disorder","aliases":["impulse-control disorders","impulse-control disorder","impulse control disorder","pathological gambling","compulsive shopping","compulsive gambling","impulse control","hypersexuality"],"def":"Compulsive gambling, shopping, eating, or hypersexuality — a warning tied to dopamine partial agonists like aripiprazole.","wiki":null,"category":"adverse-effect"},{"term":"metabolic acidosis","aliases":["non-anion-gap metabolic acidosis","metabolic acidosis","acidosis"],"def":"Excess acid in the blood; topiramate causes a non-anion-gap metabolic acidosis via carbonic-anhydrase inhibition.","wiki":null,"category":"adverse-effect"},{"term":"ndri","aliases":["norepinephrine-dopamine reuptake inhibitor","ndri"],"def":"Norepinephrine-dopamine reuptake inhibitor (bupropion) — no serotonergic activity, so no sexual dysfunction or weight gain.","wiki":null,"category":"class"},{"term":"orexin receptor antagonist","aliases":["dual orexin receptor antagonist","orexin receptor antagonist","dora"],"def":"A hypnotic that blocks wake-promoting orexin signalling to allow sleep, with no GABA action and no dependence.","wiki":null,"category":"class"},{"term":"rapid cycling","aliases":["rapid cycling"],"def":"Bipolar disorder with four or more mood episodes in a year; antidepressants can worsen it.","wiki":"bipolar","category":"disorder"},{"term":"seizure disorder","aliases":["seizure disorder","epilepsy"],"def":"A tendency to recurrent unprovoked seizures; bupropion is contraindicated because it lowers the seizure threshold.","wiki":null,"category":"disorder"},{"term":"therapeutic drug monitoring","aliases":["therapeutic drug monitoring","therapeutic drug level","trough concentration","blood-level target","therapeutic window","trough level","serum level","drug level"],"def":"Measuring blood drug levels to keep them in a target range — used for lithium, valproate, clozapine, and some TCAs.","wiki":null,"category":"pharmacology"},{"term":"therapeutic index","aliases":["narrow therapeutic index","narrow-therapeutic-index","therapeutic window","therapeutic index","narrow index"],"def":"The margin between an effective dose and a toxic one; lithium's is narrow, so levels and toxicity are a constant concern.","wiki":null,"category":"pharmacology"},{"term":"therapeutic window","aliases":["therapeutic drug monitoring","therapeutic serum range","therapeutic window","therapeutic range","therapeutic index"],"def":"The blood-level range where a drug works without toxicity; nortriptyline is unusual in that levels above it lose efficacy.","wiki":null,"category":"pharmacology"},{"term":"toxidrome","aliases":["toxidrome"],"def":"A characteristic cluster of signs pointing to a class of poisoning (e.g., anticholinergic, sympathomimetic, opioid).","wiki":null,"category":"pharmacology"},{"term":"crp","aliases":["c-reactive protein","crp"],"def":"C-reactive protein — an inflammation marker that rises alongside troponin in myocarditis.","wiki":null,"category":"lab"},{"term":"dopamine agonist","aliases":["dopamine agonist"],"def":"A drug that stimulates dopamine receptors; can trigger impulse-control disorders like gambling and hypersexuality.","wiki":null,"category":"pharmacology"},{"term":"dress","aliases":["drug reaction with eosinophilia and systemic symptoms"],"def":"A severe multi-organ drug hypersensitivity with rash, fever and eosinophilia (e.g. carbamazepine, linked to HLA-A*3101).","wiki":null,"category":"adverse-effect"},{"term":"dress syndrome","aliases":["dress syndrome"],"def":"Drug reaction with eosinophilia and systemic symptoms — rash, fever, eosinophilia, and multi-organ involvement.","wiki":null,"category":"adverse-effect"},{"term":"immediate-release","aliases":["immediate-release","immediate release","ir formulation"],"def":"A formulation that releases its full dose right after intake — quick onset but shorter, less steady coverage than extended-release.","wiki":null,"category":"pharmacology"},{"term":"melatonin agonist","aliases":["melatonin receptor agonist","melatonin agonist","melatonergic"],"def":"A drug (ramelteon) that promotes sleep via melatonin MT1/MT2 receptors and the circadian system, without dependence.","wiki":null,"category":"class"},{"term":"troponin","aliases":["troponin"],"def":"A blood marker of heart-muscle injury; it rises in clozapine-induced myocarditis.","wiki":null,"category":"lab"},{"term":"atypical depression","aliases":["rejection sensitivity","atypical depression","mood reactivity"],"def":"A depression subtype with mood reactivity, hypersomnia, hyperphagia, leaden paralysis, and rejection sensitivity.","wiki":"mdd","category":"disorder"},{"term":"bradykinesia","aliases":["bradykinesia"],"def":"Slowness of movement; a core feature of drug-induced parkinsonism from dopamine (D2) blockade.","wiki":"eps","category":"sign"},{"term":"cross-taper","aliases":["cross-tapering","cross-taper","cross taper"],"def":"Gradually lowering one drug while raising its replacement to switch safely, e.g., alprazolam onto clonazepam.","wiki":null,"category":"pharmacology"},{"term":"hyperarousal","aliases":["hyperarousal symptoms","hyperarousal"],"def":"A PTSD symptom cluster of heightened arousal: hypervigilance, exaggerated startle, irritability, and poor concentration.","wiki":null,"category":"symptom"},{"term":"inr","aliases":["international normalized ratio","inr"],"def":"A measure of blood-clotting time on warfarin; it shifts when enzyme inducers or inhibitors change warfarin levels.","wiki":null,"category":"lab"},{"term":"livedo reticularis","aliases":["livedo reticularis","mottled skin"],"def":"A mottled, net-like purplish skin discoloration; a characteristic amantadine side effect.","wiki":null,"category":"sign"},{"term":"neutropenia","aliases":["low neutrophil count","severe neutropenia","low neutrophils","neutropenia","low anc"],"def":"A low neutrophil count; severe neutropenia (ANC <0.5) means stopping clozapine and generally not rechallenging.","wiki":null,"category":"adverse-effect"},{"term":"positive allosteric modulator","aliases":["positive allosteric modulator","allosterically potentiates","allosteric modulator"],"def":"A drug binding a site separate from the main one that amplifies the natural ligand's effect — how benzodiazepines boost GABA.","wiki":null,"category":"pharmacology"},{"term":"releaser","aliases":["releaser"],"def":"A drug that actively pushes neurotransmitter out of the neuron; amphetamines release dopamine and norepinephrine, unlike a reuptake blocker.","wiki":null,"category":"pharmacology"},{"term":"rems","aliases":["restricted program","rems"],"def":"A restricted-distribution safety program with mandatory monitoring for high-risk drugs, e.g., esketamine.","wiki":null,"category":"pharmacology"},{"term":"therapeutic drug level","aliases":["therapeutic drug level","therapeutic level","trough level","serum level","drug level"],"def":"The blood concentration used to guide dosing, usually drawn as a trough (e.g., lithium 12-hour level) to keep it effective but non-toxic.","wiki":null,"category":"lab"},{"term":"alpha-2 agonist","aliases":["central alpha-2 agonist","α2-adrenergic agonist","alpha-2 agonist","alpha-2-agonist","alpha2 agonist","α2a agonist","a2 agonist","α2-agonist","α2 agonist"],"def":"Agents (clonidine, guanfacine, dexmedetomidine) that lower sympathetic outflow; used in ADHD, agitation, and withdrawal.","wiki":null,"category":"class"},{"term":"anhedonia","aliases":["loss of interest","loss of pleasure","anhedonia","anhedonic"],"def":"Loss of the ability to feel pleasure or interest in normally enjoyable activities — a core depressive symptom.","wiki":"mdd","category":"symptom"},{"term":"aplastic anemia","aliases":["aplastic anaemia","aplastic anemia"],"def":"Bone-marrow failure producing low red cells, white cells, and platelets; a rare carbamazepine risk.","wiki":null,"category":"adverse-effect"},{"term":"bpsd","aliases":["behavioural and psychological symptoms of dementia","bpsd"],"def":"Behavioural and psychological symptoms of dementia — agitation, aggression, psychosis, wandering; try non-drug measures first.","wiki":"dementia","category":"symptom"},{"term":"deuteration","aliases":["deuteration","deuterated"],"def":"Swapping hydrogen for heavier deuterium to slow metabolism and smooth drug levels — as in deutetrabenazine.","wiki":null,"category":"pharmacology"},{"term":"diabetic ketoacidosis","aliases":["diabetic ketoacidosis","dka"],"def":"A dangerous hyperglycemic emergency with ketosis and acidosis; olanzapine can precipitate new-onset diabetes and DKA.","wiki":null,"category":"adverse-effect"},{"term":"dissociation","aliases":["depersonalisation","depersonalization","derealisation","derealization","dissociation","dissociative"],"def":"Feeling detached from reality (derealization) or from oneself (depersonalization); can occur during panic attacks.","wiki":null,"category":"symptom"},{"term":"dysgeusia","aliases":["metallic taste","altered taste","dysgeusia","bad taste"],"def":"A distorted sense of taste; the characteristic metallic aftertaste of zopiclone and a local effect of sublingual asenapine.","wiki":null,"category":"adverse-effect"},{"term":"dyslipidemia","aliases":["dyslipidaemia","raised lipids","dyslipidemia"],"def":"Abnormal blood lipids (high LDL/triglycerides); part of antipsychotic metabolic syndrome.","wiki":null,"category":"adverse-effect"},{"term":"mixed features","aliases":["mixed features","mixed episode","mixed states"],"def":"Depressive and manic symptoms occurring together in one episode, raising suicide risk and complicating treatment.","wiki":"bipolar","category":"disorder"},{"term":"peripheral neuropathy","aliases":["peripheral neuropathy"],"def":"Damage to peripheral nerves causing numbness, tingling or weakness; phenelzine can cause it via vitamin B6 depletion.","wiki":null,"category":"adverse-effect"},{"term":"rebound insomnia","aliases":["rebound insomnia"],"def":"Transiently worse insomnia after stopping a hypnotic; common with short-acting Z-drugs and benzodiazepines.","wiki":null,"category":"adverse-effect"},{"term":"schizoaffective disorder","aliases":["schizoaffective disorder","schizoaffective"],"def":"A disorder combining features of schizophrenia with prominent mood episodes; psychosis also occurs apart from the mood symptoms.","wiki":null,"category":"disorder"},{"term":"steady state","aliases":["steady state","steady-state"],"def":"The point where drug intake and elimination balance, giving stable levels; usually reached after about five half-lives.","wiki":null,"category":"pharmacology"},{"term":"amenorrhea","aliases":["missed periods","amenorrhoea","amenorrhea"],"def":"Absence of menstrual periods; with antipsychotics it signals prolactin elevation from D2 blockade.","wiki":null,"category":"sign"},{"term":"angioedema","aliases":["angioedema"],"def":"Deep tissue swelling of the lips, tongue, or airway that can be life-threatening.","wiki":null,"category":"adverse-effect"},{"term":"beers list","aliases":["beers criteria","beers-listed","beers list","beers-type","beers-list"],"def":"A list of medications (e.g., benzodiazepines, anticholinergics) best avoided in older adults due to harm risk.","wiki":null,"category":"other"},{"term":"brain zaps","aliases":["electric-shock sensations","brain zaps"],"def":"Brief electric-shock-like sensations, often on head movement; a classic antidepressant discontinuation symptom.","wiki":"discontinuation-syndrome","category":"symptom"},{"term":"carbonic anhydrase inhibition","aliases":["carbonic anhydrase inhibition","carbonic-anhydrase inhibition","carbonic anhydrase inhibitor"],"def":"Blockade of carbonic anhydrase (topiramate) causing paresthesia, metabolic acidosis, kidney stones and glaucoma.","wiki":null,"category":"pharmacology"},{"term":"cogwheel rigidity","aliases":["cogwheel rigidity","cogwheeling"],"def":"Ratchet-like resistance felt when passively moving a limb — a parkinsonian sign, here from antipsychotic D2 blockade.","wiki":null,"category":"sign"},{"term":"dysarthria","aliases":["slurred speech","dysarthria"],"def":"Slurred, poorly articulated speech from impaired motor control; appears in moderate-to-severe lithium toxicity.","wiki":null,"category":"sign"},{"term":"first-dose phenomenon","aliases":["first-dose hypotension","first-dose phenomenon","first dose phenomenon","first-dose effect"],"def":"Marked orthostatic hypotension or syncope after the first dose of an alpha-1 blocker like prazosin; start low at bedtime.","wiki":null,"category":"adverse-effect"},{"term":"hypercalcemia","aliases":["hyperparathyroidism","hypercalcaemia","hypercalcemia"],"def":"A high blood calcium level; chronic lithium can raise PTH and calcium (hyperparathyroidism).","wiki":null,"category":"adverse-effect"},{"term":"hypersomnia","aliases":["hypersomnia"],"def":"Excessive sleepiness or sleeping too much; can be a feature of atypical depression.","wiki":null,"category":"symptom"},{"term":"miosis","aliases":["pupillary constriction","pinpoint pupils","miosis","miotic"],"def":"Excessive pupil constriction (pinpoint pupils) — a classic sign of opioid or cholinergic effect.","wiki":null,"category":"sign"},{"term":"obstructive sleep apnea","aliases":["obstructive sleep apnoea","obstructive sleep apnea","sleep apnea"],"def":"Repeated upper-airway collapse during sleep causing apneas and daytime sleepiness; treated with CPAP.","wiki":null,"category":"disorder"},{"term":"oral cleft","aliases":["cleft lip/palate","cleft palate","oral clefts","oral cleft","cleft lip"],"def":"A cleft of the lip or palate; topiramate in pregnancy raises this risk.","wiki":null,"category":"other"},{"term":"pinpoint pupils","aliases":["pinpoint pupils","miosis"],"def":"Markedly constricted pupils — a classic sign of opioid intoxication or overdose.","wiki":null,"category":"sign"},{"term":"rhabdomyolysis","aliases":["rhabdomyolysis"],"def":"Breakdown of muscle releasing myoglobin that can injure the kidneys; a complication of NMS and severe serotonin syndrome.","wiki":null,"category":"syndrome"},{"term":"sari","aliases":["saris","sari"],"def":"Serotonin antagonist/reuptake inhibitor — trazodone; sedating via alpha-1 and H1 blockade, used low-dose for insomnia.","wiki":null,"category":"class"},{"term":"acute pancreatitis","aliases":["acute pancreatitis","pancreatitis"],"def":"Inflammation of the pancreas (severe abdominal pain, raised lipase); a recognized valproate adverse effect warranting drug discontinuation.","wiki":null,"category":"adverse-effect"},{"term":"alpha-1 antagonist","aliases":["α1-adrenergic antagonist","alpha-1 antagonist","alpha-1 blocker","α1 antagonist","α1 blockade","α1-blocker"],"def":"An alpha-1 adrenergic blocker (prazosin) that lowers blood pressure and eases PTSD nightmares; watch for first-dose hypotension.","wiki":null,"category":"class"},{"term":"alpha-1 blocker","aliases":["alpha-1 antagonist","alpha-1 blocker","alpha1 blockade","alpha1 blocker","α1 antagonist","α1 blocker","α1-blocker","a1 blocker"],"def":"An alpha-1-adrenergic antagonist (prazosin) used off-label for PTSD nightmares; can cause first-dose orthostatic hypotension.","wiki":null,"category":"class"},{"term":"binge eating disorder","aliases":["binge eating disorder","binge eating"],"def":"Recurrent episodes of eating large amounts with loss of control, without the compensatory purging of bulimia.","wiki":null,"category":"disorder"},{"term":"creatine kinase","aliases":["creatinine kinase","creatine kinase","elevated ck"],"def":"A muscle enzyme that rises with muscle breakdown; it climbs markedly (often >1000) in neuroleptic malignant syndrome.","wiki":null,"category":"lab"},{"term":"cross-tolerance","aliases":["cross-tolerance"],"def":"When tolerance to one drug carries over to another in the same class, letting one substitute for another (e.g., in withdrawal).","wiki":null,"category":"pharmacology"},{"term":"delirium tremens","aliases":["alcohol-withdrawal delirium","delirium tremens","dts"],"def":"Severe alcohol-withdrawal delirium — confusion, autonomic surge, and seizures; benzodiazepines are first-line and life-saving.","wiki":"aud","category":"syndrome"},{"term":"diabetes insipidus","aliases":["nephrogenic diabetes insipidus","diabetes insipidus","nephrogenic di"],"def":"Kidney resistance to antidiuretic hormone causing large volumes of dilute urine and thirst; a chronic lithium effect.","wiki":null,"category":"adverse-effect"},{"term":"hyperammonemic encephalopathy","aliases":["hyperammonemic encephalopathy","hyperammonaemia","hyperammonemia"],"def":"Confusion and lethargy from high blood ammonia; a valproate complication that can occur even at normal drug levels.","wiki":null,"category":"adverse-effect"},{"term":"hypomania","aliases":["hypomanias","hypomania","hypomanic"],"def":"A milder high than mania — elevated, energised mood with reduced sleep need, without marked impairment or psychosis.","wiki":"bipolar","category":"disorder"},{"term":"mu receptor","aliases":["mu opioid receptor","mu receptor","mu-opioid"],"def":"The main opioid receptor; agonists at it relieve pain but cause euphoria and respiratory depression.","wiki":null,"category":"pharmacology"},{"term":"opioid overdose","aliases":["opioid intoxication","opioid overdose","opioid toxicity","opiate overdose"],"def":"A life-threatening opioid effect: depressed breathing, pinpoint pupils, and unresponsiveness — reversed with naloxone.","wiki":"oud","category":"syndrome"},{"term":"oral hypoesthesia","aliases":["oral hypoaesthesia","oral hypoesthesia","oral hypaesthesia","tongue numbness","hypoesthesia"],"def":"Numbness of the mouth and tongue — a characteristic local effect of the sublingual antipsychotic asenapine.","wiki":null,"category":"adverse-effect"},{"term":"pancreatitis","aliases":["pancreatitis"],"def":"Inflammation of the pancreas causing severe abdominal pain; a recognized valproate adverse effect.","wiki":null,"category":"adverse-effect"},{"term":"paralytic ileus","aliases":["gastrointestinal hypomotility","bowel obstruction","paralytic ileus"],"def":"Severe gut slowing that can halt bowel movement; a clozapine risk worsened by anticholinergics.","wiki":null,"category":"adverse-effect"},{"term":"paresthesia","aliases":["pins-and-needles","pins and needles","paresthesias","paraesthesia","paresthesia","tingling"],"def":"Abnormal tingling or 'pins and needles' sensation; a topiramate effect stemming from carbonic-anhydrase inhibition.","wiki":null,"category":"symptom"},{"term":"polydipsia","aliases":["polydipsia"],"def":"Excessive thirst and drinking, often paired with polyuria; seen with lithium's effect on the kidney.","wiki":null,"category":"symptom"},{"term":"polyuria","aliases":["polyuria"],"def":"Passing abnormally large volumes of urine; classically from lithium-induced nephrogenic diabetes insipidus or high glucose.","wiki":null,"category":"sign"},{"term":"positive symptoms","aliases":["positive symptoms","positive features","positive symptom"],"def":"The 'added' symptoms of psychosis — delusions, hallucinations, and disorganized speech or behaviour.","wiki":"schizophrenia","category":"symptom"},{"term":"postpartum psychosis","aliases":["postpartum psychosis"],"def":"A psychiatric emergency of acute psychosis and mood disturbance soon after childbirth, requiring urgent admission.","wiki":null,"category":"disorder"},{"term":"pruritus","aliases":["pruritus"],"def":"Itching; hydroxyzine is used for its antihistamine anti-itch effect.","wiki":null,"category":"symptom"},{"term":"re-narcotization","aliases":["re-narcotization","renarcotization"],"def":"Return of opioid overdose when short-acting naloxone wears off before the longer-acting opioid does.","wiki":null,"category":"other"},{"term":"restless legs","aliases":["restless legs syndrome","restless legs"],"def":"An urge to move the legs with uncomfortable sensations, worse at rest and at night; can drive insomnia.","wiki":null,"category":"disorder"},{"term":"torticollis","aliases":["torticollis"],"def":"Sustained twisting or tilting of the neck; an acute drug-induced dystonia is one cause and responds to anticholinergics.","wiki":"eps","category":"sign"},{"term":"aims","aliases":["abnormal involuntary movement scale"],"def":"Abnormal Involuntary Movement Scale — a standardised exam to screen for and track tardive dyskinesia.","wiki":null,"category":"lab"},{"term":"anticipatory anxiety","aliases":["anticipatory anxiety"],"def":"Worry and dread about a future event or feared situation before it happens.","wiki":null,"category":"symptom"},{"term":"ciwa","aliases":["ciwa-guided","ciwa score","ciwa"],"def":"A structured scale rating alcohol-withdrawal severity to guide symptom-triggered benzodiazepine dosing.","wiki":null,"category":"other"},{"term":"ciwa-ar","aliases":["ciwa-ar","ciwa"],"def":"A validated scale rating alcohol-withdrawal severity to guide symptom-triggered benzodiazepine dosing.","wiki":null,"category":"lab"},{"term":"cognitive slowing","aliases":["word-finding difficulty","cognitive slowing"],"def":"Slowed thinking and trouble finding words — a recognized topiramate cognitive effect.","wiki":null,"category":"adverse-effect"},{"term":"egfr","aliases":["glomerular filtration rate","egfr"],"def":"A measure of kidney filtration; low values raise levels of renally cleared drugs like lithium and paliperidone.","wiki":null,"category":"lab"},{"term":"enzyme inhibition","aliases":["enzyme inhibition","enzyme inhibitor","cyp inhibition","cyp inhibitor"],"def":"A drug blocking a metabolic enzyme, raising levels of drugs it clears and risking toxicity (e.g. fluvoxamine on CYP1A2).","wiki":null,"category":"pharmacology"},{"term":"growth suppression","aliases":["growth suppression"],"def":"Slowed height and weight gain in children on long-term stimulants; monitor on a growth chart.","wiki":null,"category":"adverse-effect"},{"term":"malignant hyperthermia","aliases":["malignant hyperthermia"],"def":"A rare inherited reaction to certain anaesthetics causing extreme hyperthermia and rigidity; a differential for NMS.","wiki":null,"category":"syndrome"},{"term":"myoclonus","aliases":["fasciculations","myoclonus","myoclonic"],"def":"Sudden, brief involuntary muscle jerks; seen in serotonin syndrome and in moderate-to-severe lithium toxicity.","wiki":null,"category":"sign"},{"term":"nassa","aliases":["noradrenergic and specific serotonergic antidepressant","nassa"],"def":"Mirtazapine's class — a noradrenergic and specific serotonergic antidepressant that boosts release via alpha-2 blockade.","wiki":null,"category":"class"},{"term":"psychomotor retardation","aliases":["psychomotor retardation","psychomotor slowing","slowed-down"],"def":"Visible slowing of movement, speech and thought; a neurovegetative feature of depression (contrast psychomotor agitation).","wiki":null,"category":"symptom"},{"term":"sialorrhea","aliases":["hypersalivation","sialorrhoea","sialorrhea","drooling"],"def":"Excess saliva and drooling — a characteristic, paradoxical clozapine effect.","wiki":null,"category":"adverse-effect"},{"term":"trigeminal neuralgia","aliases":["trigeminal neuralgia"],"def":"Sudden, severe electric-shock facial pain in the trigeminal nerve distribution; carbamazepine is first-line.","wiki":null,"category":"disorder"},{"term":"agoraphobia","aliases":["agoraphobia","agoraphobic"],"def":"Fear and avoidance of situations where escape feels hard or help unavailable; often develops after panic attacks.","wiki":null,"category":"disorder"},{"term":"cataplexy","aliases":["cataplexy-like","cataplexy"],"def":"Sudden loss of muscle tone triggered by emotion, classically part of narcolepsy.","wiki":null,"category":"symptom"},{"term":"child-pugh","aliases":["child-pugh","child pugh"],"def":"A score grading the severity of liver cirrhosis (class A-C) that guides drug choice and dosing.","wiki":null,"category":"lab"},{"term":"ego-dystonic","aliases":["ego-dystonic"],"def":"Describes thoughts or urges that feel alien and distressing to the person — typical of OCD obsessions.","wiki":null,"category":"other"},{"term":"flashback","aliases":["flashbacks","flashback"],"def":"A vivid, intrusive re-experiencing of a trauma as if it were happening now.","wiki":null,"category":"symptom"},{"term":"floppy iris syndrome","aliases":["intraoperative floppy iris syndrome","floppy iris syndrome"],"def":"Iris billowing during cataract surgery; flag alpha-1-blocker use (e.g., tamsulosin, prazosin) to the eye surgeon beforehand.","wiki":null,"category":"adverse-effect"},{"term":"grandiosity","aliases":["grandiosity","grandiose"],"def":"Inflated self-esteem or belief in special powers or importance — a core manic symptom.","wiki":"bipolar","category":"symptom"},{"term":"hunter criteria","aliases":["hunter criteria"],"def":"A diagnostic rule for serotonin syndrome: a serotonergic drug plus clonus or specific autonomic/neuromuscular signs.","wiki":"serotonin-syndrome","category":"other"},{"term":"hypervigilance","aliases":["hypervigilance","hypervigilant"],"def":"A heightened, constant scanning for threat — a hyperarousal feature of PTSD.","wiki":null,"category":"symptom"},{"term":"hypothyroidism","aliases":["underactive thyroid","hypothyroidism","hypothyroid"],"def":"An underactive thyroid (fatigue, weight gain, low mood, constipation); a chronic lithium effect — monitor TSH.","wiki":null,"category":"adverse-effect"},{"term":"laryngospasm","aliases":["laryngospasm"],"def":"Spasm of the vocal cords that can obstruct the airway — a feared severe dystonic reaction.","wiki":null,"category":"sign"},{"term":"multimodal antidepressant","aliases":["multimodal antidepressant","multimodal serotonergic"],"def":"An antidepressant combining serotonin reuptake inhibition with direct serotonin-receptor modulation — vortioxetine.","wiki":null,"category":"class"},{"term":"opioid toxidrome","aliases":["opioid toxidrome","opioid overdose"],"def":"The opioid-overdose triad: pinpoint pupils, respiratory depression, and reduced consciousness.","wiki":"oud","category":"syndrome"},{"term":"primary polydipsia","aliases":["primary polydipsia"],"def":"Excessive water drinking not driven by a physiologic need, which can dilute blood sodium (and lithium) levels.","wiki":null,"category":"disorder"},{"term":"rem sleep behaviour disorder","aliases":["rem sleep behaviour disorder","rem sleep behavior disorder"],"def":"Acting out dreams from loss of the normal muscle paralysis of REM sleep; can herald neurodegenerative disease.","wiki":null,"category":"disorder"},{"term":"sleep paralysis","aliases":["sleep paralysis"],"def":"Temporary inability to move when falling asleep or waking; can be triggered by orexin-antagonist hypnotics.","wiki":null,"category":"symptom"},{"term":"sympathomimetic toxicity","aliases":["sympathomimetic toxidrome","sympathomimetic toxicity"],"def":"Overdrive of adrenergic activity — tachycardia, hypertension, agitation, and dilated pupils — from stimulants or MAOI–decongestant combos.","wiki":null,"category":"syndrome"},{"term":"trismus","aliases":["trismus"],"def":"Lockjaw — painful clenching from spasm of the jaw muscles.","wiki":null,"category":"sign"},{"term":"wernicke encephalopathy","aliases":["wernicke encephalopathy","wernicke-korsakoff","wernicke"],"def":"A thiamine-deficiency emergency: confusion, ophthalmoplegia, and ataxia; give thiamine before any glucose.","wiki":"aud","category":"syndrome"},{"term":"first-episode psychosis","aliases":["first-episode psychosis","first episode psychosis"],"def":"A person's initial episode of psychotic illness; early referral to specialized services improves outcomes.","wiki":"schizophrenia","category":"other"},{"term":"flight of ideas","aliases":["flight of ideas","racing thoughts"],"def":"Rapid shifting between loosely connected thoughts — a feature of mania.","wiki":"bipolar","category":"symptom"},{"term":"pressured speech","aliases":["pressured speech"],"def":"Rapid, hard-to-interrupt speech driven by internal urgency — a classic sign of mania.","wiki":"bipolar","category":"symptom"}]};
